```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define NB_MOTS 5
#define TAILLE_MAX 100
#define NB_ESSAIS 7

void choisirMot(char *motMystere) {
    char *listeMots[NB_MOTS] = {
        "pendu",
        "dynamique",
        "ordinateur",
        "programmation",
        "clavier"
    };

    strcpy(motMystere, listeMots[rand() % NB_MOTS]);
}

int lettreDansMot(char lettre, const char *mot) {
    for (size_t i = 0; i < strlen(mot); i++) {
        if (lettre == mot[i]) {
            return 1;
        }
    }
    return 0;
}

int main() {
    srand(time(NULL));
    char motMystere[TAILLE_MAX] = {0};
    choisirMot(motMystere);

    char *motMasque = malloc(strlen(motMystere) + 1);
    for (size_t i = 0; i < strlen(motMystere); i++) {
        motMasque[i] = '-';
    }
    motMasque[strlen(motMystere)] = '\0';

    int essaisRestants = NB_ESSAIS;
    int gagne = 0;
    char lettreProposee;

    printf("Bienvenue dans le jeu du pendu!\n");

    while (!gagne && essaisRestants > 0) {
        printf("\nMot à deviner : %s\n", motMasque);
        printf("Vous avez %d essais restants. Proposez une lettre : ", essaisRestants);
        scanf(" %c", &lettreProposee);

        if (lettreDansMot(lettreProposee, motMystere)) {
            for (size_t i = 0; i < strlen(motMystere); i++) {
                if (motMystere[i] == lettreProposee) {
                    motMasque[i] = lettreProposee;
                }
            }
        } else {
            essaisRestants--;
            printf("La lettre '%c' ne se trouve pas dans le mot mystère.\n", lettreProposee);
        }

        if (!lettreDansMot('-', motMasque)) {
            gagne = 1;
        }
    }

    if (gagne) {
        printf("\nFélicitations ! Vous avez trouvé le mot mystère : %s\n", motMystere);
    } else {
        printf("\nDommage... Vous avez perdu. Le mot mystère était : %s\n", motMystere);
    }
    free(motMasque);
    return 0;
}
