public class DataFeedHistorization {

    public static void main(String[] args) {
        SparkSession sparkSession = SparkSession.builder()
            .appName("Data Feed Historization")
            .config("spark.some.config.option", "some-value")
            .getOrCreate();
        JavaSparkContext javaSparkContext = new JavaSparkContext(sparkSession.sparkContext());

        // Load data feeds
        String sourcedDataFeedPath = args[0];
        String historicalDataFeedPath = args[1];
        JavaRDD<String> sourcedDataFeed = javaSparkContext.textFile(sourcedDataFeedPath);
        JavaRDD<String> historicalDataFeed = javaSparkContext.textFile(historicalDataFeedPath);

        // Convert records to pair RDD with key as technical fields (assuming comma-separated)
        JavaPairRDD<String, String> sourcedPairRDD = sourcedDataFeed.mapToPair(createTechnicalFieldKeyPair());
        JavaPairRDD<String, String> historicalPairRDD = historicalDataFeed.mapToPair(createTechnicalFieldKeyPair());

        // Categorize records as new, updated, and constant
        JavaPairRDD<String, String> newRecords = sourcedPairRDD.subtractByKey(historicalPairRDD);
        JavaPairRDD<String, Tuple2<String, String>> joinedRecords = sourcedPairRDD.join(historicalPairRDD);
        JavaPairRDD<String, String> updatedRecords = joinedRecords.filter(pair -> !pair._2._1.equals(pair._2._2)).mapToPair(pair -> new Tuple2<>(pair._1, pair._2._1));
        JavaPairRDD<String, String> constantRecords = joinedRecords.filter(pair -> pair._2._1.equals(pair._2._2)).mapToPair(pair -> new Tuple2<>(pair._1, pair._2._1));

        // Find union of sourced data feed and delta from historical data feed
        JavaPairRDD<String, String> unionRDD = newRecords.union(updatedRecords).union(historicalPairRDD);

        // Save output
        String outputPath = args[2];
        unionRDD.map(pair -> pair._1 + "," + pair._2).saveAsTextFile(outputPath);

        sparkSession.stop();
    }

    private static PairFunction<String, String, String> createTechnicalFieldKeyPair() {
        return record -> {
            String[] fields = record.split(",", -1);
            int n = fields.length;

            // Assuming first half fields are technical fields and the rest are non-technical fields
            StringBuilder technicalFieldsKey = new StringBuilder();
            for (int i = 0; i < (n / 2); i++) {
                technicalFieldsKey.append(fields[i]);
                if (i < (n / 2) - 1) {
                    technicalFieldsKey.append(",");
                }
            }

            return new Tuple2<>(technicalFieldsKey.toString(), record);
        };
    }
}
